class Solution(object):
    def hasSpecialSubstring(self, s, k):
        n = len(s)
        for i in range(n - k + 1):
            sub = s[i:i + k]
            if len(set(sub)) == 1:
                if (i == 0 or s[i - 1] != sub[0]) and (i + k == n or s[i + k] != sub[0]):
                    return True
        return False
